function countdown(n) {
  if (n <= 0) {           // base case: stop
    console.log("Done!");
    return;
  }
  console.log(n);
  countdown(n - 1);       // recursive case: smaller problem
}

countdown(3);
// 3
// 2
// 1
// Done!

